import { precacheAndRoute } from 'workbox-precaching';

// Precache the assets generated by Vite
precacheAndRoute(self.__WB_MANIFEST);

self.addEventListener('install', () => {
    self.skipWaiting();
});

self.addEventListener('activate', (event) => {
    event.waitUntil(clients.claim());
});

// Handle Push Notifications
self.addEventListener('push', function (event) {
    if (!event.data) return;
    
    try {
        const data = event.data.json();
        
        const options = {
            body: data.body || 'New ecosystem activity detected.',
            icon: '/pwa-192x192.png',
            badge: '/pwa-192x192.png',
            vibrate: [200, 100, 200, 100, 400],
            tag: 'admin-alert-' + (data.type || 'general'),
            renotify: true, // Wake up screen even if same tag
            requireInteraction: true, // Keep notification visible until dismissed
            data: {
                dateOfArrival: Date.now(),
                url: data.url || '/admin'
            },
            actions: [
                { action: 'view', title: 'Open Hub' }
            ]
        };

        event.waitUntil(
            self.registration.showNotification(data.title || 'Executive Alert', options)
        );
    } catch (e) {
        // Fallback for non-JSON payloads
        const text = event.data.text();
        event.waitUntil(
            self.registration.showNotification('Executive Alert', {
                body: text,
                icon: '/pwa-192x192.png',
                tag: 'admin-alert-fallback',
                renotify: true
            })
        );
    }
});

// Handle notification click
self.addEventListener('notificationclick', function (event) {
    event.notification.close();
    
    const urlToOpen = (event.notification.data && event.notification.data.url) ? event.notification.data.url : '/admin';

    event.waitUntil(
        clients.matchAll({ type: 'window', includeUncontrolled: true }).then(function (clientList) {
            for (let i = 0; i < clientList.length; i++) {
                let client = clientList[i];
                if (client.url === urlToOpen && 'focus' in client) {
                    return client.focus();
                }
            }
            if (clients.openWindow) {
                return clients.openWindow(urlToOpen);
            }
        })
    );
});
